import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function CreateProject() {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    skills_required: '',
    budget_min: '',
    budget_max: '',
    duration_days: '',
    status: 'open'
  });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Debug: Check token and form data
    const token = localStorage.getItem('access');
    console.log('Token:', token);
    console.log('Form data being sent:', formData);
    
    try {
      const response = await axios.post('http://127.0.0.1:8000/api/projects/', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      console.log('Success response:', response.data);
      alert('Project created successfully!');
      navigate('/projects');
      
    } catch (error) {
      console.error('Full error object:', error);
      
      if (error.response) {
        // Server responded with error
        console.log('Error status:', error.response.status);
        console.log('Error data:', error.response.data);
        
        // Show specific error message
        if (error.response.status === 401) {
          alert('Authentication failed. Please login again.');
        } else if (error.response.status === 403) {
          alert('Only clients can create projects.');
        } else {
          alert('Failed: ' + JSON.stringify(error.response.data));
        }
        
      } else if (error.request) {
        // Request made but no response
        console.log('No response from server');
        alert('Server not responding. Check if backend is running.');
        
      } else {
        // Something else happened
        console.log('Error message:', error.message);
        alert('Error: ' + error.message);
      }
    }
  };

  return (
    <div className="container">
      <h2>Create New Project</h2>
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Title:</label>
          <input
            type="text"
            name="title"
            value={formData.title}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Description:</label>
          <textarea
            name="description"
            value={formData.description}
            onChange={handleChange}
            required
            rows="4"
          />
        </div>

        <div className="form-group">
          <label>Skills Required (comma separated):</label>
          <input
            type="text"
            name="skills_required"
            value={formData.skills_required}
            onChange={handleChange}
            placeholder="React, Django, Python"
            required
          />
        </div>

        <div className="form-group">
          <label>Minimum Budget (₹):</label>
          <input
            type="number"
            name="budget_min"
            value={formData.budget_min}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Maximum Budget (₹):</label>
          <input
            type="number"
            name="budget_max"
            value={formData.budget_max}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Duration (days):</label>
          <input
            type="number"
            name="duration_days"
            value={formData.duration_days}
            onChange={handleChange}
            required
          />
        </div>

        <button type="submit">Create Project</button>
        <button type="button" onClick={() => navigate('/projects')}>Cancel</button>
      </form>
    </div>
  );
}

export default CreateProject;
